searchData={"items":[{"type":"module","title":"Haikuify","doc":"# Haikuify\n\nGenerate Heroku-like memorable random names to use in your apps or anywhere else.","ref":"Haikuify.html"},{"type":"function","title":"Haikuify.build/1","doc":"","ref":"Haikuify.html#build/1"},{"type":"function","title":"Haikuify.build/2","doc":"","ref":"Haikuify.html#build/2"},{"type":"function","title":"Haikuify.build/3","doc":"Generate a memorable name.\n\n`token` is the first parameter, and sets either a string suffix or the range for the token (i.e. the number) from 0 to n.\nDefaults to `9999`.\n\n`delimiter` is the second parameter, and it's the string that joins the sections.\nDefaults to `\"-\"`.","ref":"Haikuify.html#build/3"},{"type":"function","title":"Examples - Haikuify.build/3","doc":"# Default\n    iex> Haikuify.build # => \"morning-star\"\n\n    # Token range\n    iex> Haikuify.build(100) # => \"summer-dawn-24\"\n\n    # Don't include the token\n    iex> Haikuify.build(0) # => \"ancient-frost\"\n\n    # Use a different delimiter\n    iex> Haikuify.build(9999, \".\") # => \"frosty.leaf.8347\"\n\n    # No token, no delimiter\n    iex> Haikuify.build(0, \"\") # => \"twilightbreeze\"\n\n    # Text token, no delimiter\n    iex> Haikuify.build(\"suffix\", \"\") # => \"twilightbreezesuffix\"\n\n    # Text token, different delimiter\n    iex> Haikuify.build(\"suffix\", \".\") # => \"frosty.leaf.suffix\"\n\n    # Text token with spaces, different delimiter\n    iex> Haikuify.build(\"end of suffix\", \".\") # => \"frosty.leaf.and.of.suffix\"","ref":"Haikuify.html#build/3-examples"},{"type":"function","title":"Haikuify.token/3","doc":"","ref":"Haikuify.html#token/3"}],"content_type":"text/markdown","producer":{"name":"ex_doc","version":[48,46,51,52,46,50]}}